let guide; let view='home';
const $=s=>document.querySelector(s), won=n=>new Intl.NumberFormat('ko-KR',{maximumFractionDigits:2}).format(n);
const meta={
 '01_economics':{name:'경제',tag:'MACRO & POLICY',desc:'거시지표를 금리·환율·자산가격의 언어로 연결합니다.',bullets:['GDP·물가·고용의 동시 해석','통화·재정정책의 전달경로','경기국면과 자산배분'],note:'숫자 하나로 결론 내리지 않습니다. 수준·전년동기비·전월비, 그리고 수요 충격인지 공급 충격인지부터 분해한 다음 금융시장 가격변수로 번역합니다.',sources:[['한국은행','https://www.bok.or.kr'],['KOSIS','https://kosis.kr'],['IMF Data','https://data.imf.org']]},
 '02_finance':{name:'금융·투자',tag:'INVESTMENT & VALUATION',desc:'현금흐름, 위험, 가격결정모형을 실제 투자 의사결정으로 묶습니다.',bullets:['채권 듀레이션·신용스프레드','DCF·상대가치·재무분석','파생·포트폴리오 위험관리'],note:'상품명보다 현금흐름 구조를 먼저 읽습니다. 그다음 할인율·성장률·신용위험·유동성위험을 분리하고, 가정의 민감도를 확인합니다.',sources:[['KRX','https://global.krx.co.kr'],['금융감독원 DART','https://dart.fss.or.kr'],['금융투자협회','https://www.kofia.or.kr']]},
 '03_planning':{name:'재무설계·세금',tag:'PERSONAL FINANCE',desc:'목표·제약조건·현금흐름을 기준으로 실행 가능한 재무계획을 설계합니다.',bullets:['생애주기 현금흐름과 보장','세후 수익률·계좌 배치','상속·증여의 사전 점검'],note:'세금은 “수익률의 뒷단”이 아니라 설계 변수입니다. 세법·한도·적용연도는 변동하므로 계산 결과를 신고·투자 판단의 근거로 단독 사용하지 않습니다.',sources:[['국세청','https://www.nts.go.kr'],['국세법령정보시스템','https://taxlaw.nts.go.kr'],['금융위원회','https://www.fsc.go.kr']]},
 '04_law':{name:'법률·윤리',tag:'LAW & CONDUCT',desc:'권유·거래·정보의 경계에서 법률과 직무윤리를 실무 언어로 해석합니다.',bullets:['적합성·적정성·설명의무','불공정거래와 미공개정보','투자자보호·분쟁 예방'],note:'법률은 암기 목록보다 사실관계의 순서가 핵심입니다. 고객·상품·행위·정보·시점·증빙을 분리하여 확인하고, 최신 조문과 감독규정을 대조합니다.',sources:[['국가법령정보센터','https://www.law.go.kr'],['금융감독원','https://www.fss.or.kr'],['금융소비자정보포털','https://fine.fss.or.kr']]}
};
async function boot(){guide=await fetch('content.json').then(r=>r.json());renderNav();renderHome();bindGlobal()}
function renderNav(){const items=[['home','홈'],...Object.entries(meta).map(([k,v])=>[k,v.name]),['dictionary','용어']];for(const id of ['primaryNav','mobileNav'])$( '#'+id).innerHTML=items.map(([k,n])=>`<button data-view="${k}" class="${view===k?'active':''}">${n}</button>`).join('')}
function go(next){view=next;renderNav();next==='home'?renderHome():next==='dictionary'?renderDictionary():renderTopic(next);window.scrollTo({top:0,behavior:'instant'})}
function renderHome(){$('#app').innerHTML=`<div class="page"><section class="hero"><p class="eyebrow">FINANCE KNOWLEDGE SYSTEM · v${guide.version}</p><h1>시험의 지식을<br>판단의 도구로.</h1><p>경제·금융투자·재무설계·법률윤리를 한 화면에서 복습하고 설명하는 전문가용 필드북입니다. 원문 노트의 깊이는 유지하고, 핵심 판단 틀과 실용 도구를 앞에 배치했습니다.</p></section><section class="grid quick-grid"><article class="card metric"><small>LIVE MARKET SNAPSHOT</small><strong id="kospi" class="live-value">KOSPI 불러오는 중</strong><small id="marketTime">Stooq 공개 시세 · 지연 또는 실패 가능</small></article><article class="card metric"><small>STUDY MODE</small><strong>4개 분야</strong><small>핵심 프레임 → 심화 노트</small></article><article class="card metric"><small>PRACTICAL TOOLS</small><strong>3개</strong><small>채권 · 세후수익 · 규정 점검</small></article><article class="card metric"><small>TRUST</small><strong>공식 출처</strong><small>변동 항목은 원문 확인</small></article></section><section class="section"><div class="section-title"><h2>네 개의 전문 영역</h2><p>핵심을 먼저 잡고, 필요한 경우 원문으로 내려갑니다.</p></div><div class="grid field-grid">${Object.entries(meta).map(([k,v],i)=>`<button class="card field-card" data-view="${k}"><span class="field-number">0${i+1}</span><h3>${v.name}</h3><p>${v.desc}</p><ul>${v.bullets.map(x=>`<li>${x}</li>`).join('')}</ul></button>`).join('')}</div></section><section class="section"><div class="section-title"><h2>바로 써보는 도구</h2><p>교육용 시뮬레이션이며, 투자·세무·법률 자문을 대체하지 않습니다.</p></div><div class="grid tool-grid"><article class="card tool-card"><h3>채권 가격 민감도</h3><p>수정듀레이션과 금리변화로 1차 가격효과를 빠르게 점검합니다.</p><button data-view="02_finance">금융·투자로</button></article><article class="card tool-card"><h3>세후 수익률</h3><p>명목수익률에서 세율을 차감해 세후 복리 결과를 비교합니다.</p><button data-view="03_planning">재무설계로</button></article><article class="card tool-card"><h3>권유 전 점검</h3><p>적합성·설명의무·기록 보존의 핵심 질문을 확인합니다.</p><button data-view="04_law">법률·윤리로</button></article></div></section></div>`;loadMarket()}
function renderTopic(slug){const chapter=guide.chapters.find(c=>c.slug===slug),m=meta[slug],heads=[...new DOMParser().parseFromString(chapter.html,'text/html').querySelectorAll('h2,h3')].slice(0,12);const content=chapter.html.replace(/<h1>.*?<\/h1>/,'');$('#app').innerHTML=`<div class="page"><header class="topic-head"><p class="eyebrow">${m.tag}</p><h1>${m.name}</h1><p>${m.desc}</p></header><div class="topic-layout"><aside class="topic-aside">${heads.map((h,i)=>`<button data-jump="h-${i}">${h.textContent}</button>`).join('')}</aside><article><div class="expert-note"><strong>전문가의 판단 순서</strong>${m.note}</div>${special(slug)}<div class="study-body" id="studyBody">${content}</div><section class="tool-panel"><h3>검증 가능한 출처</h3><p>제도·세율·공시·통계처럼 바뀔 수 있는 정보는 아래 1차 출처에서 최종 확인합니다.</p><div class="source-list">${m.sources.map(s=>`<a href="${s[1]}" target="_blank" rel="noreferrer">${s[0]} ↗</a>`).join('')}</div></section></article></div></div>`;$('#studyBody').querySelectorAll('h2,h3').forEach((h,i)=>h.id='h-'+i);document.querySelectorAll('[data-jump]').forEach(b=>b.onclick=()=>$('#'+b.dataset.jump)?.scrollIntoView({behavior:'smooth'}));bindTools(slug)}
function special(s){if(s==='01_economics')return `<section class="tool-panel"><h3>거시 해석 지도</h3><p>금리와 환율을 독립 변수로 보지 말고, 성장·물가·정책·위험선호의 결과로 연결합니다.</p><div class="formula-board"><div><b>국민소득</b><code>Y = C + I + G + (X − M)</code></div><div><b>실질금리 근사</b><code>r ≈ i − πᵉ</code></div><div><b>채권 1차 효과</b><code>ΔP/P ≈ −Dₘₒd × Δy</code></div></div><div class="quiz" data-answer="b"><button data-q="a">물가상승은 언제나 수요 과열이다</button><button data-q="b">충격의 원인을 수요·공급으로 분해한다</button><button data-q="c">환율은 수출입만으로 결정된다</button></div></section>`;if(s==='02_finance')return `<section class="tool-panel"><h3>채권 가격 민감도</h3><p>수정듀레이션 기반 1차 근사입니다. 큰 금리변화에서는 볼록성·현금흐름 재투자·스프레드를 별도로 고려하세요.</p><div class="calculator"><label>수정듀레이션<input id="duration" type="number" value="5" step="0.1"></label><label>금리 변화(bp)<input id="bps" type="number" value="25" step="1"></label><label>보유금액(원)<input id="principal" type="number" value="10000000" step="100000"></label><div class="result-box"><span>추정 가격 변동</span><strong id="bondResult">-</strong></div></div></section>`;if(s==='03_planning')return `<section class="tool-panel"><h3>세후 복리 수익률 비교</h3><p>교육용 단순 계산입니다. 실제 과세는 금융상품·계좌·손익통산·보유기간·개인별 요건에 따라 달라집니다.</p><div class="calculator"><label>원금(원)<input id="taxPrincipal" type="number" value="10000000" step="100000"></label><label>연 수익률(%)<input id="returnRate" type="number" value="6" step="0.1"></label><label>가정 세율(%)<input id="taxRate" type="number" value="15.4" step="0.1"></label><label>기간(년)<input id="years" type="number" value="3" min="1" step="1"></label><div class="result-box"><span>세후 추정 평가액</span><strong id="taxResult">-</strong></div></div></section>`;return `<section class="tool-panel"><h3>금융상품 권유 전 점검</h3><p>아래 세 요소가 모두 확인되어야 권유 프로세스가 완결됩니다.</p><div class="formula-board"><div><b>고객 적합성</b><code>목적 · 재산 · 경험 · 위험선호</code></div><div><b>상품 이해</b><code>위험 · 비용 · 손실 가능성</code></div><div><b>기록과 설명</b><code>설명의 근거 · 확인 · 보존</code></div></div><div class="quiz" data-answer="c"><button data-q="a">수익 가능성만 설명하면 충분하다</button><button data-q="b">고객이 서명하면 설명의무는 사라진다</button><button data-q="c">상품과 고객 특성의 적합성을 먼저 확인한다</button></div></section>`}
function bindTools(s){document.querySelectorAll('.quiz button').forEach(b=>b.onclick=()=>{const q=b.closest('.quiz');q.querySelectorAll('button').forEach(x=>x.className=x.dataset.q===q.dataset.answer?'correct':x===b?'wrong':'');});if(s==='02_finance'){['duration','bps','principal'].forEach(id=>$('#'+id).oninput=()=>{const d=+$('#duration').value||0,b=(+$('#bps').value||0)/10000,p=+$('#principal').value||0,change=-d*b;$('#bondResult').textContent=`${change>=0?'+':''}${(change*100).toFixed(2)}% · ${won(p*change)}원`;});$('#duration').oninput()}if(s==='03_planning'){['taxPrincipal','returnRate','taxRate','years'].forEach(id=>$('#'+id).oninput=()=>{const p=+$('#taxPrincipal').value||0,r=(+$('#returnRate').value||0)/100,t=(+$('#taxRate').value||0)/100,y=+$('#years').value||0;$('#taxResult').textContent=`${won(p*Math.pow(1+r*(1-t),y))}원`;});$('#taxPrincipal').oninput()}}
async function loadMarket(){const node=$('#kospi');try{const tx=await fetch('https://stooq.com/q/l/?s=%5Ekospi&f=sd2t2c&e=csv').then(r=>r.text()),row=tx.trim().split(/\r?\n/)[1].split(',');const val=Number(row.at(-1));if(!Number.isFinite(val))throw Error();node.textContent='KOSPI '+won(val);node.className='live-value live-up';$('#marketTime').textContent=`Stooq · ${row[1]} ${row[2]} 기준`; }catch{node.textContent='KOSPI 시세 확인';node.className='live-value';$('#marketTime').innerHTML='<a href="https://global.krx.co.kr" target="_blank" rel="noreferrer">KRX에서 확인 ↗</a>'}}
function renderDictionary(){const c=guide.chapters.find(x=>x.slug==='05_dictionary');$('#app').innerHTML=`<div class="page"><header class="topic-head"><p class="eyebrow">GLOSSARY</p><h1>용어 사전</h1><p>원문 노트의 용어를 검색해 필요한 맥락으로 바로 돌아갑니다.</p></header><article class="study-body">${c.html.replace(/<h1>.*?<\/h1>/,'')}</article></div>`}
function bindGlobal(){$(document).addEventListener('click',e=>{const b=e.target.closest('[data-view]');if(b)go(b.dataset.view)});$('#homeButton').onclick=()=>go('home');$('#searchButton').onclick=()=>{$('#searchDialog').showModal();$('#termSearch').focus();search('')};$('#termSearch').oninput=e=>search(e.target.value)}
function search(q){const terms=[...guide.chapters].flatMap(c=>{const d=new DOMParser().parseFromString(c.html,'text/html');return [...d.querySelectorAll('h2,h3,h4,h5')].map(h=>({title:h.textContent.trim(),chapter:c.slug,text:(h.nextElementSibling?.textContent||'').slice(0,100)}))}).filter(x=>!q||`${x.title} ${x.text}`.toLowerCase().includes(q.toLowerCase())).slice(0,20);$('#searchResults').innerHTML=terms.map(x=>`<button class="search-result" data-view="${x.chapter}"><b>${x.title}</b><span>${meta[x.chapter]?.name||'용어'} · ${x.text}</span></button>`).join('')||'<p>일치하는 항목이 없습니다.</p>'}
boot().catch(()=>{$('#app').innerHTML='<div class="page"><p>콘텐츠를 불러오지 못했습니다. 새로고침 후 다시 시도하세요.</p></div>'});
